import { Router } from 'express';
import pool from '../database.js';

const router = Router();

// 🟢 Mostrar formulario de agregar persona
router.get('/add', (req, res) => {
  res.render('personas/add');
});

// 🟢 Crear persona
router.post('/add', async (req, res) => {
  try {
    const { name, lastname, age } = req.body;
    const newPersona = { name, lastname, age };
    await pool.query('INSERT INTO personas SET ?', [newPersona]);
    res.redirect('/list');
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: err.message });
  }
});

// 🟢 Listar personas
router.get('/list', async (req, res) => {
  try {
    const [result] = await pool.query('SELECT * FROM personas');
    res.render('personas/list', { personas: result }); // ✅ usar render, no redirect
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: err.message }); // ✅ json minúscula
  }
});

// 🟢 Mostrar formulario para editar
router.get('/edit/:id', async (req, res) => {
  try {
    const { id } = req.params; // ✅ corregido
    const [persona] = await pool.query('SELECT * FROM personas WHERE id = ?', [id]);
    if (persona.length === 0) return res.redirect('/list');
    res.render('personas/edit', { persona: persona[0] });
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: err.message });
  }
});

// 🟢 Actualizar persona
router.post('/edit/:id', async (req, res) => {
  try {
    const { id } = req.params;
    const { name, lastname, age } = req.body;
    const editPersona = { name, lastname, age };
    await pool.query('UPDATE personas SET ? WHERE id = ?', [editPersona, id]); // ✅ corregido
    res.redirect('/list');
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: err.message });
  }
});

// 🟢 Eliminar persona
router.get('/delete/:id', async (req, res) => {
  try {
    const { id } = req.params; // ✅ corregido
    await pool.query('DELETE FROM personas WHERE id = ?', [id]);
    res.redirect('/list'); // ✅ redirect, no render
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: err.message });
  }
});

export default router;
